
  // ── NAV SCROLL ──
  const nav = document.getElementById('mainNav');
  window.addEventListener('scroll', () => {
    nav.classList.toggle('scrolled', window.scrollY > 60);
  });

  // ── MOBILE MENU ──
  let menuOpen = false;

  function toggleMenu(e) {
    if (e) { e.stopPropagation(); e.preventDefault(); }
    menuOpen = !menuOpen;
    const menu = document.getElementById('mobileMenu');
    const hb1 = document.getElementById('hb1');
    const hb2 = document.getElementById('hb2');
    const hb3 = document.getElementById('hb3');
    if (!menu) return;

    // Show/hide mobile menu
    menu.style.display = menuOpen ? 'flex' : 'none';
    document.body.style.overflow = menuOpen ? 'hidden' : '';

    // Hamburger → X animation
    if (hb1 && hb2 && hb3) {
      if (menuOpen) {
        hb1.style.cssText = 'transform:rotate(45deg) translate(5px,5px); background:#E8D18F;';
        hb2.style.cssText = 'opacity:0; transform:scaleX(0);';
        hb3.style.cssText = 'transform:rotate(-45deg) translate(5px,-5px); background:#E8D18F;';
      } else {
        hb1.style.cssText = '';
        hb2.style.cssText = '';
        hb3.style.cssText = '';
      }
    }
  }

  // Hamburger button — both click and touchend
  const hamburgerBtn = document.getElementById('hamburger');
  if (hamburgerBtn) {
    hamburgerBtn.addEventListener('click', toggleMenu);
    hamburgerBtn.addEventListener('touchend', function(e) {
      e.preventDefault();
      e.stopPropagation();
      toggleMenu();
    });
  }

  // Close menu when a mobile nav link is tapped/clicked
  document.querySelectorAll('#mobileMenu a, #mobileMenuClose').forEach(el => {
    el.addEventListener('click', () => { if (menuOpen) toggleMenu(); });
  });

  // Close if clicking the menu backdrop (not its children)
  const mobileMenuEl = document.getElementById('mobileMenu');
  if (mobileMenuEl) {
    mobileMenuEl.addEventListener('click', (e) => {
      if (e.target === mobileMenuEl) toggleMenu();
    });
  }

    // Keyboard support for hamburger
  if (hamburgerBtn) {
    hamburgerBtn.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleMenu(); }
    });
  }

  // ── SCROLL REVEAL ──
  const revealEls = document.querySelectorAll('.reveal');
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });
  revealEls.forEach(el => observer.observe(el));

  // ── DIRECTIONAL REVEAL: add from-left/from-right to two-col grids ──
  document.querySelectorAll('#essence > .reveal:first-child, #hospitality .hosp-layout > .reveal:first-child, #ritual .ritual-layout > .reveal:first-child, #gifting .gifting-layout > .reveal:first-child').forEach(el => el.classList.add('from-left'));
  document.querySelectorAll('#essence > .reveal:last-child, #hospitality .hosp-layout > .reveal:last-child, #ritual .ritual-layout > .reveal:last-child, #gifting .gifting-layout > .reveal:last-child').forEach(el => el.classList.add('from-right'));

  // ── GOLD PARTICLES ──
  const container = document.getElementById('particles');
  for (let i = 0; i < 22; i++) {
    const p = document.createElement('div');
    p.className = 'particle';
    p.style.cssText = `
      left: ${Math.random() * 100}%;
      width: ${Math.random() * 2.5 + 1}px;
      height: ${Math.random() * 2.5 + 1}px;
      animation-duration: ${Math.random() * 12 + 10}s;
      animation-delay: ${Math.random() * 8}s;
      --drift: ${(Math.random() - 0.5) * 120}px;
      opacity: ${Math.random() * 0.5 + 0.2};
    `;
    container.appendChild(p);
  }

  // ── FORM SUBMIT → GOOGLE SHEETS ──
  // ↓ PASTE YOUR GOOGLE APPS SCRIPT WEB APP URL HERE ↓
  const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbyfhgu9rTttqw9quMlhGLlxrbD0_eaA45DisqQMJaGCgB66H6uZ6sW8sdNbLIBmDfvWiw/exec';

  function handleSubmit(e) {
    e.preventDefault();

    const btn  = document.getElementById('submitBtn');
    const form = document.getElementById('contactForm');

    // Collect form data
    const data = {
      timestamp:   new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
      name:        document.getElementById('name').value.trim(),
      company:     document.getElementById('company').value.trim(),
      role:        document.getElementById('role').value.trim(),
      city:        document.getElementById('city').value.trim(),
      email:       document.getElementById('email').value.trim(),
      phone:       document.getElementById('phone').value.trim(),
      requirement: document.getElementById('requirement').value.trim(),
      timing:      document.getElementById('timing').value,
    };

    // Validate required fields
    if (!data.name || !data.company || !data.city || !data.email || !data.phone) {
      alert('Please fill in all required fields.');
      return;
    }

    // Loading state
    btn.textContent = 'Sending…';
    btn.style.opacity = '0.7';
    btn.disabled = true;

    // Check if URL has been configured
    if (GOOGLE_SCRIPT_URL === 'YOUR_GOOGLE_APPS_SCRIPT_URL_HERE') {
      // Demo mode — just show success (remove this block after setting up Google Sheets)
      setTimeout(() => {
        form.style.display = 'none';
        const success = document.getElementById('formSuccess');
        success.style.display = 'block';
        success.classList.add('visible');
      }, 800);
      return;
    }

    // Send to Google Sheets via Apps Script
    fetch(GOOGLE_SCRIPT_URL, {
      method: 'POST',
      mode: 'no-cors',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    .then(() => {
      // Success — no-cors means we can't read response, but if no error it worked
      form.style.display = 'none';
      const success = document.getElementById('formSuccess');
      success.style.display = 'block';
      success.classList.add('visible');
    })
    .catch((err) => {
      // Network error fallback
      console.error('Form submission error:', err);
      btn.textContent = 'Book a Call →';
      btn.style.opacity = '1';
      btn.disabled = false;
      alert('Something went wrong. Please email us directly at aujalgold@gmail.com');
    });
  }

  // ── PREVENT HORIZONTAL OVERFLOW (safety net) ──
  document.querySelectorAll('section, footer, nav').forEach(el => {
    el.style.maxWidth = '100vw';
    el.style.overflowX = 'hidden';
  });

  // ── GOLDEN CURSOR — mouse/desktop only, never on touch ──
  (function() {
    // Detect touch/mobile: skip everything if no fine pointer
    const hasFineMouse = window.matchMedia('(hover: hover) and (pointer: fine)').matches;
    if (!hasFineMouse) return;   // ← exit immediately on mobile/tablet/touch

    const dot  = document.getElementById('golden-cursor');
    const ring = document.getElementById('golden-cursor-ring');
    if (!dot || !ring) return;

    // Activate — add class so CSS shows the elements
    document.body.classList.add('has-mouse');

    let mx = -200, my = -200, rx = -200, ry = -200;

    // Dot: instant
    document.addEventListener('mousemove', e => {
      mx = e.clientX; my = e.clientY;
      dot.style.left = mx + 'px';
      dot.style.top  = my + 'px';
    });

    // Ring: lagged via RAF
    (function loop() {
      rx += (mx - rx) * 0.13;
      ry += (my - ry) * 0.13;
      ring.style.left = rx + 'px';
      ring.style.top  = ry + 'px';
      requestAnimationFrame(loop);
    })();

    // Hover expansion on interactive elements
    const sel = 'a,button,[onclick],.product-btn,.use-case,.pillar-card,.gold-cell,.founder-card,.gift-feature,.ritual-step,.nav-cta,.btn-primary,.btn-ghost,.social-icon,.v3d-thumb,input,select,textarea,label';
    document.querySelectorAll(sel).forEach(el => {
      el.addEventListener('mouseenter', () => document.body.classList.add('cursor-hover'));
      el.addEventListener('mouseleave', () => document.body.classList.remove('cursor-hover'));
    });

    // Click feedback
    document.addEventListener('mousedown', () => document.body.classList.add('cursor-clicking'));
    document.addEventListener('mouseup',   () => document.body.classList.remove('cursor-clicking'));

    // Hide when leaving window
    document.addEventListener('mouseleave', () => { dot.style.opacity='0'; ring.style.opacity='0'; });
    document.addEventListener('mouseenter', () => { dot.style.opacity='1'; ring.style.opacity='1'; });
  })();



  // ── FORM SUBMIT ──
  
  // ── PREVENT HORIZONTAL OVERFLOW (safety net) ──
  document.querySelectorAll('section, footer, nav').forEach(el => {
    el.style.maxWidth = '100vw';
    el.style.overflowX = 'hidden';
  });

  // ── 3D BOTTLE VIEWER ──
  const v3dImages = [
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
  ];
  const v3dLabels = [
    "Front · Gold Label",
    "Three-Quarter · Gold Flakes",
    "Side · Slim Profile",
    "Side · Narrow Edge",
    "Back · Ingredients Label",
  ];
  let v3dCurrent = 0;
  let v3dDragStart = null;
  let v3dAutoTimer = null;
  let v3dInteracted = false;

  const v3dImg   = document.getElementById('v3d-img');
  const v3dHint  = document.getElementById('v3d-hint');
  const v3dLabel = document.getElementById('v3d-label');
  const v3dThumbs = document.querySelectorAll('.v3d-thumb');

  function setBottleView(idx, fromDrag) {
    v3dCurrent = ((idx % v3dImages.length) + v3dImages.length) % v3dImages.length;
    v3dImg.style.opacity = '0';
    setTimeout(() => {
      v3dImg.src = v3dImages[v3dCurrent];
      v3dImg.style.opacity = '1';
      if (v3dLabel) v3dLabel.textContent = v3dLabels[v3dCurrent];
    }, 80);

    // Update thumb borders
    v3dThumbs.forEach((t,i) => {
      t.style.borderColor = i === v3dCurrent ? 'rgba(197,160,72,0.9)' : 'rgba(197,160,72,0.2)';
    });

    if (!v3dInteracted && fromDrag) {
      v3dInteracted = true;
      if (v3dHint) v3dHint.style.opacity = '0';
      setTimeout(() => { if (v3dHint) v3dHint.style.display='none'; }, 400);
    }
    resetAutoRotate();
  }

  function resetAutoRotate() {
    clearTimeout(v3dAutoTimer);
    v3dAutoTimer = setTimeout(() => {
      setBottleView(v3dCurrent + 1);
    }, 4000);
  }

  // Start auto-rotate
  resetAutoRotate();

  const viewer = document.getElementById('viewer3d');
  if (viewer) {
    // Mouse drag
    viewer.addEventListener('mousedown', e => {
      v3dDragStart = e.clientX;
      viewer.style.cursor = 'grabbing';
      clearTimeout(v3dAutoTimer);
    });
    window.addEventListener('mousemove', e => {
      if (v3dDragStart === null) return;
      const delta = e.clientX - v3dDragStart;
      if (Math.abs(delta) > 60) {
        setBottleView(v3dCurrent + (delta < 0 ? 1 : -1), true);
        v3dDragStart = e.clientX;
      }
    });
    window.addEventListener('mouseup', () => {
      v3dDragStart = null;
      viewer.style.cursor = 'grab';
    });

    // Touch drag
    let touchStart = null;
    viewer.addEventListener('touchstart', e => {
      touchStart = e.touches[0].clientX;
      clearTimeout(v3dAutoTimer);
    }, {passive:true});
    viewer.addEventListener('touchmove', e => {
      if (touchStart === null) return;
      const delta = e.touches[0].clientX - touchStart;
      if (Math.abs(delta) > 50) {
        setBottleView(v3dCurrent + (delta < 0 ? 1 : -1), true);
        touchStart = e.touches[0].clientX;
      }
    }, {passive:true});
    viewer.addEventListener('touchend', () => { touchStart = null; resetAutoRotate(); });

    // Scroll wheel to cycle
    viewer.addEventListener('wheel', e => {
      e.preventDefault();
      setBottleView(v3dCurrent + (e.deltaY > 0 ? 1 : -1), true);
    }, {passive:false});
  }

